// 排版表格：表名黑体小五号居中，表格与页面等宽，跨页重复表头，表头黑体五号居中加粗，表格内容宋体五号靠左对齐
var doc = Application.ActiveDocument;
var tables = doc.Tables;

for (var i = 1; i <= tables.Count; i++) {
    var table = tables.Item(i);

    // 设置表格宽度与页面等宽
    var pageWidth = doc.PageSetup.PageWidth - doc.PageSetup.LeftMargin - doc.PageSetup.RightMargin;
    table.PreferredWidthType = 1; // wdPreferredWidthPercent
    table.PreferredWidth = 100;

    // 设置跨页重复表头
    if (table.Rows.Count > 1) {
        table.Rows.FirstRow.HeadingFormat = true;
    }

    // 处理表头行（第一行）
    var headerRow = table.Rows.FirstRow;
    for (var j = 1; j <= headerRow.Cells.Count; j++) {
        var cell = headerRow.Cells.Item(j);
        var range = cell.Range;
        range.Font.Name = "黑体";
        range.Font.Size = 10.5; // 五号
        range.Font.Bold = true;
        range.ParagraphFormat.Alignment = 1; // wdAlignParagraphCenter
    }

    // 处理表格内容（除表头外的行）
    for (var r = 2; r <= table.Rows.Count; r++) {
        var row = table.Rows.Item(r);
        for (var k = 1; k <= row.Cells.Count; k++) {
            var cellContent = row.Cells.Item(k);
            var contentRange = cellContent.Range;
            contentRange.Font.Name = "宋体";
            contentRange.Font.Size = 10.5; // 五号
            contentRange.Font.Bold = false;
            contentRange.ParagraphFormat.Alignment = 0; // wdAlignParagraphLeft
        }
    }

    // 处理表名（表格上方的段落）
    if (i <= tables.Count) {
        var tableStart = table.Range.Start;
        var paraBefore = null;

        // 查找表格前的段落作为表名
        for (var p = 1; p <= doc.Paragraphs.Count; p++) {
            var para = doc.Paragraphs.Item(p);
            if (para.Range.End >= tableStart) {
                if (p > 1) {
                    paraBefore = doc.Paragraphs.Item(p - 1);
                }
                break;
            }
        }

        if (paraBefore != null) {
            var paraText = paraBefore.Range.Text.replace(/\r/g, "").replace(/\n/g, "").trim();
            // 判断是否为表名（包含"表"字）
            if (paraText.indexOf("表") >= 0 && paraText.length < 50) {
                paraBefore.Range.Font.Name = "黑体";
                paraBefore.Range.Font.Size = 9; // 小五号
                paraBefore.Range.Font.Bold = true;
                paraBefore.Range.ParagraphFormat.Alignment = 1; // 居中
            }
        }
    }
}

return "表格排版完成";

